css:
.crm-pipeline-fb {
  --surface: var(--block-bg-color, #15151A);
  --surface-raised: #1B1B22;
  --input-surface: var(--input-bg-color, #1B1B22);
  --ink: var(--color-text, #F4F4F7);
  --muted: var(--color-gray-500, #8A8A96);
  --label-ink: var(--color-gray-700, #C2C2CC);
  --line: var(--color-gray-200, rgba(255,255,255,.07));
  --accent: var(--color-primary, #FFD21E);
  --accent-2: var(--color-secondary, #FF3D8B);
  container-type: inline-size;
  display: flex;
  flex-wrap: wrap;
  align-items: flex-end;
  gap: 14px;
  color: var(--ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 14px;
  padding: 14px 16px;
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
  box-sizing: border-box;
}
.crm-pipeline-fb .fb-head {
  display: flex;
  flex-direction: column;
  gap: 3px;
  margin-right: auto;
  min-width: 140px;
}
.crm-pipeline-fb .fb-eyebrow {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  font-weight: 700;
  font-size: 11px;
  line-height: 1.2;
  letter-spacing: .13em;
  text-transform: uppercase;
  color: var(--label-ink);
}
.crm-pipeline-fb .fb-eyebrow::before {
  content: "";
  flex: none;
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--accent);
  box-shadow: 0 0 10px -2px color-mix(in srgb, var(--accent) 70%, transparent);
}
.crm-pipeline-fb .fb-title {
  margin: 0;
  font-weight: 800;
  font-size: 18px;
  line-height: 1.15;
  letter-spacing: -.01em;
  color: var(--ink);
}
.crm-pipeline-fb .fb-controls {
  display: flex;
  flex-wrap: wrap;
  align-items: flex-end;
  gap: 12px;
}
.crm-pipeline-fb .fb-field {
  display: flex;
  flex-direction: column;
  gap: 5px;
}
.crm-pipeline-fb .fb-label {
  font-weight: 700;
  font-size: 10.5px;
  line-height: 1.2;
  letter-spacing: .1em;
  text-transform: uppercase;
  color: var(--muted);
}
.crm-pipeline-fb select,
.crm-pipeline-fb input[type="date"] {
  font-family: inherit;
  font-weight: 600;
  font-size: 13px;
  line-height: 1;
  font-variant-numeric: tabular-nums;
  padding: 8px 10px;
  min-height: 44px;
  border-radius: 10px;
  border: 1px solid var(--line);
  background: var(--input-surface);
  color: var(--ink);
  color-scheme: dark;
  cursor: pointer;
  box-sizing: border-box;
  transition: border-color .15s ease, box-shadow .15s ease, background .15s ease;
}
.crm-pipeline-fb select { min-width: 150px; }
.crm-pipeline-fb .fb-range-inputs {
  display: flex;
  align-items: center;
  gap: 8px;
}
.crm-pipeline-fb .fb-range-sep {
  font-weight: 600;
  font-size: 11px;
  line-height: 1;
  color: var(--muted);
}
.crm-pipeline-fb select:hover,
.crm-pipeline-fb input[type="date"]:hover {
  border-color: color-mix(in srgb, var(--accent) 35%, var(--line));
  background: var(--surface-raised);
}
.crm-pipeline-fb select:not(:has(option[value=""]:checked)) {
  border-color: color-mix(in srgb, var(--accent-2) 55%, var(--line));
  box-shadow: inset 0 0 0 1px color-mix(in srgb, var(--accent-2) 30%, transparent),
              0 0 18px -8px color-mix(in srgb, var(--accent-2) 65%, transparent);
}
.crm-pipeline-fb select:not(:has(option[value=""]:checked)):hover {
  border-color: color-mix(in srgb, var(--accent-2) 70%, var(--line));
}
.crm-pipeline-fb .fb-clear {
  font-family: inherit;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
  font-size: 12px;
  line-height: 1;
  letter-spacing: .04em;
  text-transform: uppercase;
  padding: 9px 16px;
  min-height: 44px;
  border-radius: 10px;
  border: 1px solid var(--accent);
  background: transparent;
  color: var(--accent);
  cursor: pointer;
  box-sizing: border-box;
  transition: background .15s ease, color .15s ease, box-shadow .15s ease, transform .1s ease;
}
.crm-pipeline-fb .fb-clear:hover {
  background: var(--accent);
  color: var(--body-bg-color, #0B0B0D);
  box-shadow: 0 0 20px -6px color-mix(in srgb, var(--accent) 60%, transparent);
}
.crm-pipeline-fb .fb-clear:active { transform: translateY(1px); }
.crm-pipeline-fb select:focus-visible,
.crm-pipeline-fb input[type="date"]:focus-visible,
.crm-pipeline-fb .fb-clear:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}
@media (prefers-reduced-motion: reduce) {
  .crm-pipeline-fb select,
  .crm-pipeline-fb input[type="date"],
  .crm-pipeline-fb .fb-clear { transition: none; }
  .crm-pipeline-fb .fb-clear:active { transform: none; }
}
@container (max-width: 720px) {
  .crm-pipeline-fb .fb-head { width: 100%; min-width: 0; }
  .crm-pipeline-fb select { min-width: 130px; }
}
@container (max-width: 480px) {
  .crm-pipeline-fb .fb-controls {
    flex-direction: column;
    align-items: stretch;
    width: 100%;
  }
  .crm-pipeline-fb .fb-field { width: 100%; }
  .crm-pipeline-fb select,
  .crm-pipeline-fb input[type="date"] {
    width: 100%;
    min-width: 0;
  }
  .crm-pipeline-fb .fb-range-inputs { width: 100%; }
  .crm-pipeline-fb .fb-range-inputs input[type="date"] {
    flex: 1 1 0;
    min-width: 0;
  }
  .crm-pipeline-fb .fb-clear { width: 100%; }
}
